   193|async function pollDeployUntilTerminal(deployId: string, budgetMs: number): Promise<{ status: string | null; polls: number; terminal: boolean; error: string | null }> {
   194|  const startedAt = Date.now();
   195|  let polls = 0;
   196|  let lastStatus: string | null = null;
   197|  let lastError: string | null = null;
   198|
   199|  while (Date.now() - startedAt < budgetMs) {
   200|    polls += 1;
   201|    const deploy = await fetchRenderDeploy(deployId);
   202|    lastStatus = deploy.status;
   203|    lastError = deploy.error;
   204|    if (deploy.status && TERMINAL_DEPLOY_STATES.includes(deploy.status)) {
   205|      return { status: deploy.status, polls, terminal: true, error: null };
   206|    }
   207|    await new Promise((resolve) => setTimeout(resolve, 5000));
   208|  }
   209|  return { status: lastStatus, polls, terminal: false, error: lastError };
