   589|      'Manual path: Render dashboard → Deploys → previous deploy → "Rollback to this deploy".',
   590|      '',
   591|      `_Brain: ${DEPLOYMENT_BRAIN_VERSION}_`,
   592|    ].join('\n');
   593|  }
   594|
   595|  try {
   596|    // Find the previous successful (live) deploy — skip the current one.
   597|    const listRes = await fetch(`https://api.render.com/v1/services/${serviceId}/deploys?limit=10`, {
   598|      headers: { Authorization: `Bearer ${apiKey}` },
   599|      signal: AbortSignal.timeout(10000),
   600|    });
   601|    if (!listRes.ok) {
   602|      return `## Deploy Rollback — FAILED\n\nRender API HTTP ${listRes.status} while listing deploys.\n\n_Brain: ${DEPLOYMENT_BRAIN_VERSION}_`;
   603|    }
   604|    const deploys = await listRes.json() as Array<{ deploy: Record<string, unknown> }>;
   605|    const liveDeploys = deploys
   606|      .map((d) => d.deploy)
   607|      .filter((d) => d.status === 'live' || d.status === 'deactivated');
   608|    const target = liveDeploys[1];
   609|
   610|    if (!target?.id) {
   611|      return `## Deploy Rollback — NO TARGET\n\nCould not find a previous successful deploy to roll back to.\n\n_Brain: ${DEPLOYMENT_BRAIN_VERSION}_`;
   612|    }
   613|
   614|    const rollbackRes = await fetch(`https://api.render.com/v1/services/${serviceId}/rollback`, {
   615|      method: 'POST',
   616|      headers: { Authorization: `Bearer ${apiKey}`, 'Content-Type': 'application/json' },
   617|      body: JSON.stringify({ deployId: target.id }),
   618|      signal: AbortSignal.timeout(15000),
   619|    });
   620|    const text = await rollbackRes.text();
   621|    let body: Record<string, unknown> = {};
   622|    try { body = JSON.parse(text) as Record<string, unknown>; } catch {}
   623|
   624|    return [
   625|      `## Deploy Rollback — ${rollbackRes.ok ? 'TRIGGERED' : 'FAILED'}`,
   626|      '',
   627|      `**Target deploy:** \`${target.id}\` (commit \`${short(((target.commit as Record<string, unknown>)?.id as string) ?? null)}\`)`,
   628|      `**HTTP Status:** ${rollbackRes.status}`,
   629|      `**New deploy ID:** ${(body.id as string) ?? '—'}`,
   630|      '',
   631|      rollbackRes.ok
   632|        ? 'Rollback deploy created. Run `/deploy-status` to watch it go live.'
   633|        : `Render rejected the rollback: ${text.slice(0, 300)}`,
   634|      '',
   635|      `_Brain: ${DEPLOYMENT_BRAIN_VERSION}_`,
   636|    ].join('\n');
   637|  } catch (err) {
   638|    return `## Deploy Rollback — FAILED\n\n**Error:** ${err instanceof Error ? err.message : 'Unknown error'}\n\n_Brain: ${DEPLOYMENT_BRAIN_VERSION}_`;
   639|  }
