export async function handleDeployNow(): Promise<string> {
  const taskId = `deploy-now-${Date.now()}`;
  const trigger = await triggerRenderDeploy();

  if (!trigger.ok || !trigger.deployId) {
    // Exact blocker only — never conversational prose.
    const blockerCode = !process.env.RENDER_API_KEY?.trim()
      ? 'RENDER_API_KEY_MISSING'
      : 'RENDER_TRIGGER_FAILED';
    return buildBlockedDeploymentProtocol(
      taskId,
      blockerCode,
      trigger.error ?? 'Deploy trigger failed with no deploy ID returned by Render.',
    );
  }

  // Poll briefly (bounded) so the chat reply carries real progress and the
  // request finishes before any instance rollover.
  const poll = await pollDeployUntilTerminal(trigger.deployId, 25000);

  if (!poll.terminal) {
    // Still building — RUNNING, never a fake VERIFIED.
    return buildRunningDeploymentProtocol(taskId, trigger.deployId);
  }

  if (poll.status !== 'live') {
    // Terminal but failed — BLOCKED with the exact terminal state.
    return buildBlockedDeploymentProtocol(
      taskId,
      'RENDER_DEPLOY_TERMINAL_NOT_LIVE',
      `Render deploy ${trigger.deployId} ended in terminal state \`${poll.status ?? 'unknown'}\` (not live). Check Render logs.`,
    );
  }

  // Reached LIVE — verify production serves the GitHub HEAD commit before
  // claiming VERIFIED. If the 4-way commit match fails, this is BLOCKED, not
  // VERIFIED. Never fabricate production evidence.
  const [healthRes, versionRes, github] = await Promise.all([
    fetchJson(`${PRODUCTION_API}/health`),
    fetchJson(`${PRODUCTION_API}/version`),
    fetchGitHubSha(),
  ]);
  const healthSha = extractSha(healthRes.body);
  const versionSha = extractSha(versionRes.body);
  const renderInfo = await fetchRenderDeploy(trigger.deployId);
  const renderSha = renderInfo.sha;
  const commitMatch = shasAgree(healthSha, versionSha)
    && shasAgree(github.sha, healthSha)
    && shasAgree(renderSha, healthSha);

  if (!commitMatch) {
    const reasons: string[] = [];
    if (!shasAgree(healthSha, versionSha)) reasons.push(`/health SHA ${short(healthSha)} ≠ /version SHA ${short(versionSha)}`);
    if (!shasAgree(github.sha, healthSha)) reasons.push(`GitHub SHA ${short(github.sha)} ≠ /health SHA ${short(healthSha)}`);
    if (!shasAgree(renderSha, healthSha)) reasons.push(`Render SHA ${short(renderSha)} ≠ /health SHA ${short(healthSha)}`);
    return buildBlockedDeploymentProtocol(
      taskId,
      'COMMIT_MATCH_FAILED',
      `Deploy ${trigger.deployId} reached live but production commit match failed: ${reasons.join('; ')}.`,
    );
  }

  const evidence: IVXDeploymentVerifiedEvidence = {
    githubSha: github.sha,
    renderDeployId: trigger.deployId,
    healthHttpStatus: healthRes.status,
    healthSha,
    versionHttpStatus: versionRes.status,
    versionSha,
    verifiedAt: nowIso(),
    proofLedgerEntryId: null,
  };
  return buildVerifiedDeploymentProtocol(taskId, evidence);
}

