export async function handleDeployRollback(): Promise<string> {
  const taskId = `deploy-rollback-${Date.now()}`;
  const apiKey = process.env.RENDER_API_KEY?.trim();
  const serviceId = renderServiceId();

  if (!apiKey) {
    return buildBlockedDeploymentProtocol(
      taskId,
      'RENDER_API_KEY_MISSING',
      'RENDER_API_KEY is not configured in this environment. Manual path: Render dashboard → Deploys → previous deploy → "Rollback to this deploy".',
    );
  }

  try {
    // Find the previous successful (live) deploy — skip the current one.
    const listRes = await fetch(`https://api.render.com/v1/services/${serviceId}/deploys?limit=10`, {
      headers: { Authorization: `Bearer ${apiKey}` },
      signal: AbortSignal.timeout(10000),
    });
    if (!listRes.ok) {
      return buildBlockedDeploymentProtocol(
        taskId,
        'RENDER_LIST_DEPLOYS_FAILED',
        `Render API HTTP ${listRes.status} while listing deploys.`,
      );
    }
    const deploys = await listRes.json() as Array<{ deploy: Record<string, unknown> }>;
    const liveDeploys = deploys
      .map((d) => d.deploy)
      .filter((d) => d.status === 'live' || d.status === 'deactivated');
    const target = liveDeploys[1];

    if (!target?.id) {
      return buildBlockedDeploymentProtocol(
        taskId,
        'NO_ROLLBACK_TARGET',
        'Could not find a previous successful deploy to roll back to.',
      );
    }

    const rollbackRes = await fetch(`https://api.render.com/v1/services/${serviceId}/rollback`, {
      method: 'POST',
      headers: { Authorization: `Bearer ${apiKey}`, 'Content-Type': 'application/json' },
      body: JSON.stringify({ deployId: target.id }),
      signal: AbortSignal.timeout(15000),
    });
    const text = await rollbackRes.text();
    let body: Record<string, unknown> = {};
    try { body = JSON.parse(text) as Record<string, unknown>; } catch {}

    if (!rollbackRes.ok) {
      return buildBlockedDeploymentProtocol(
        taskId,
        'RENDER_ROLLBACK_REJECTED',
        `Render rejected the rollback (HTTP ${rollbackRes.status}): ${text.slice(0, 300)}`,
      );
    }

    const newDeployId = (body.id as string) ?? null;
    // Rollback triggered a new deploy — it is RUNNING until it reaches live,
    // at which point /deploy-status or /deploy-verify will return VERIFIED.
    return buildRunningDeploymentProtocol(taskId, newDeployId);
  } catch (err) {
    return buildBlockedDeploymentProtocol(
      taskId,
      'RENDER_ROLLBACK_EXCEPTION',
      err instanceof Error ? err.message : 'Unknown error during Render rollback.',
    );
  }
}

