        'Could not find a previous successful deploy to roll back to.',
      );
    }

    const rollbackRes = await fetch(`https://api.render.com/v1/services/${serviceId}/rollback`, {
      method: 'POST',
      headers: { Authorization: `Bearer ${apiKey}`, 'Content-Type': 'application/json' },
      body: JSON.stringify({ deployId: target.id }),
      signal: AbortSignal.timeout(15000),
    });
    const text = await rollbackRes.text();
    let body: Record<string, unknown> = {};
    try { body = JSON.parse(text) as Record<string, unknown>; } catch {}

    if (!rollbackRes.ok) {
      return buildBlockedDeploymentProtocol(
        taskId,
        'RENDER_ROLLBACK_REJECTED',
        `Render rejected the rollback (HTTP ${rollbackRes.status}): ${text.slice(0, 300)}`,
      );
    }

    const newDeployId = (body.id as string) ?? null;
    // Rollback triggered a new deploy — it is RUNNING until it reaches live,
    // at which point /deploy-status or /deploy-verify will return VERIFIED.
    return buildRunningDeploymentProtocol(taskId, newDeployId);
  } catch (err) {
    return buildBlockedDeploymentProtocol(
      taskId,
      'RENDER_ROLLBACK_EXCEPTION',
      err instanceof Error ? err.message : 'Unknown error during Render rollback.',
    );
